import { execSync } from "node:child_process";
import path from "node:path";
import {
	ConfigService,
	CURRENT_STATE_FILE,
	CycleValidationService,
	DECISIONS_DIR,
	getVemDir,
	ScalableLogService,
	ValidationRulesService,
} from "@vem/core";
import chalk from "chalk";
import type { Command } from "commander";
import fs from "fs-extra";

import {
	API_URL,
	buildDeviceHeaders,
	trackCommandUsage,
	tryAuthenticatedKey,
} from "../runtime.js";

export function registerMaintenanceCommands(program: Command) {
	const getCurrentStateFromLocalCache = async () => {
		try {
			const vemDir = await getVemDir();
			const currentStatePath = path.join(vemDir, CURRENT_STATE_FILE);
			if (!(await fs.pathExists(currentStatePath))) return "";
			return await fs.readFile(currentStatePath, "utf-8");
		} catch {
			return "";
		}
	};

	const writeCurrentStateToLocalCache = async (content: string) => {
		const vemDir = await getVemDir();
		const currentStatePath = path.join(vemDir, CURRENT_STATE_FILE);
		await fs.writeFile(currentStatePath, content, "utf-8");
	};

	const resolveRemoteProjectAuth = async () => {
		const configService = new ConfigService();
		const [apiKey, projectId] = await Promise.all([
			tryAuthenticatedKey(configService),
			configService.getProjectId(),
		]);
		if (!apiKey || !projectId) return null;
		return { configService, apiKey, projectId };
	};

	const decisionCmd = program
		.command("decision")
		.description("Manage architectural decisions");

	decisionCmd
		.command("add <title>")
		.description("Record an architectural decision")
		.option("--context <text>", "Why this decision was needed")
		.option("--decision <text>", "What was decided")
		.option(
			"--tasks <ids>",
			"Comma-separated task IDs (e.g., TASK-001,TASK-002)",
		)
		.action(
			async (
				title: string,
				options: { context?: string; decision?: string; tasks?: string },
			) => {
				try {
					if (!options.context || !options.decision) {
						console.error(
							chalk.red("\nŌ£¢ Both --context and --decision are required.\n"),
						);
						console.log(chalk.gray("Example:"));
						console.log(
							chalk.gray('  vem decision add "Use Zod for validation" \\'),
						);
						console.log(
							chalk.gray('    --context "Need runtime type checking" \\'),
						);
						console.log(
							chalk.gray(
								'    --decision "Chose Zod over Yup for better TypeScript inference" \\',
							),
						);
						console.log(chalk.gray("    --tasks TASK-042,TASK-043"));
						return;
					}

					const relatedTasks = options.tasks
						? options.tasks
								.split(",")
								.map((t) => t.trim())
								.filter(Boolean)
						: undefined;

					let savedToCloud = false;
					const remoteAuth = await resolveRemoteProjectAuth();
					if (remoteAuth) {
						const response = await fetch(
							`${API_URL}/projects/${remoteAuth.projectId}/decisions`,
							{
								method: "POST",
								headers: {
									Authorization: `Bearer ${remoteAuth.apiKey}`,
									"Content-Type": "application/json",
									...(await buildDeviceHeaders(remoteAuth.configService)),
								},
								body: JSON.stringify({
									title,
									context: options.context,
									decision: options.decision,
									related_tasks: relatedTasks ?? [],
								}),
							},
						);
						if (!response.ok) {
							const payload = await response.json().catch(() => ({}));
							throw new Error(
								payload.error || "Failed to store decision in cloud",
							);
						}
						savedToCloud = true;
					}

					const configService = new ConfigService();
					await configService.recordDecision(
						title,
						options.context,
						options.decision,
						relatedTasks,
					);

					console.log(
						chalk.green(
							`\nŌ£ö Decision recorded${savedToCloud ? " (cloud + local cache)" : " (local cache)"}: ${title}`,
						),
					);
					if (relatedTasks && relatedTasks.length > 0) {
						console.log(
							chalk.gray(`  Related tasks: ${relatedTasks.join(", ")}`),
						);
					}
					console.log();
				} catch (error: any) {
					console.error(
						chalk.red(`\nŌ£¢ Failed to record decision: ${error.message}\n`),
					);
				}
			},
		);

	const contextCmd = program
		.command("context")
		.description("Manage project context and current state");

	contextCmd
		.command("show")
		.description("Show project context and current state")
		.action(async () => {
			try {
				const remoteAuth = await resolveRemoteProjectAuth();
				if (remoteAuth) {
					const response = await fetch(
						`${API_URL}/projects/${remoteAuth.projectId}/context`,
						{
							headers: {
								Authorization: `Bearer ${remoteAuth.apiKey}`,
								...(await buildDeviceHeaders(remoteAuth.configService)),
							},
						},
					);
					if (response.ok) {
						const payload = (await response.json()) as {
							context?: string;
							current_state?: string;
							decisions?: string;
							source?: string;
						};
						console.log(chalk.bold("\nProject Context"));
						console.log(chalk.gray(`Source: ${payload.source || "db"}`));
						console.log(payload.context || "");
						console.log(chalk.bold("\nCurrent State"));
						console.log(payload.current_state || "");
						if (payload.decisions && payload.decisions.trim().length > 0) {
							console.log(chalk.bold("\nDecisions"));
							console.log(payload.decisions);
						}
						console.log("");
						return;
					}
				}

				const configService = new ConfigService();
				const [context, currentState] = await Promise.all([
					configService.getContext(),
					getCurrentStateFromLocalCache(),
				]);
				console.log(chalk.bold("\nProject Context (local cache)"));
				console.log(context || "");
				console.log(chalk.bold("\nCurrent State (local cache)"));
				console.log(currentState || "");
				console.log("");
			} catch (error: any) {
				console.error(
					chalk.red(`\nŌ£¢ Failed to read context: ${error.message}\n`),
				);
			}
		});

	contextCmd
		.command("set")
		.description("Set project context and/or current state")
		.option("--context <text>", "Full CONTEXT.md content")
		.option("--current-state <text>", "Full CURRENT_STATE.md content")
		.action(async (options: { context?: string; currentState?: string }) => {
			try {
				if (
					options.context === undefined &&
					options.currentState === undefined
				) {
					console.error(
						chalk.red(
							"\nŌ£¢ Provide at least one of --context or --current-state.\n",
						),
					);
					return;
				}

				let savedToCloud = false;
				const remoteAuth = await resolveRemoteProjectAuth();
				if (remoteAuth) {
					const response = await fetch(
						`${API_URL}/projects/${remoteAuth.projectId}/context`,
						{
							method: "PUT",
							headers: {
								Authorization: `Bearer ${remoteAuth.apiKey}`,
								"Content-Type": "application/json",
								...(await buildDeviceHeaders(remoteAuth.configService)),
							},
							body: JSON.stringify({
								...(options.context !== undefined
									? { context: options.context }
									: {}),
								...(options.currentState !== undefined
									? { current_state: options.currentState }
									: {}),
							}),
						},
					);
					if (response.ok) {
						savedToCloud = true;
					} else {
						const payload = await response.json().catch(() => ({}));
						console.log(
							chalk.yellow(
								`Cloud context update failed; continuing with local cache only: ${payload.error || response.statusText}`,
							),
						);
					}
				}

				const configService = new ConfigService();
				if (options.context !== undefined) {
					await configService.updateContext(options.context);
				}
				if (options.currentState !== undefined) {
					await writeCurrentStateToLocalCache(options.currentState);
				}

				console.log(
					chalk.green(
						`\nŌ£ö Context updated${savedToCloud ? " (cloud + local cache)" : " (local cache)"}\n`,
					),
				);
			} catch (error: any) {
				console.error(
					chalk.red(`\nŌ£¢ Failed to update context: ${error.message}\n`),
				);
			}
		});

	// Diff command
	program
		.command("diff")
		.description("Show differences between local and cloud state")
		.option("--detailed", "Show detailed content diffs")
		.option("--json", "Output as JSON")
		.action(async (options: { detailed?: boolean; json?: boolean }) => {
			try {
				const { DiffService } = await import("@vem/core");
				const diffService = new DiffService();

				const result = await diffService.compareWithLastPush();

				if (options.json) {
					console.log(JSON.stringify(result, null, 2));
					return;
				}

				console.log(chalk.bold("\nVEM Diff (local vs. cloud)"));
				console.log(chalk.gray("ŌöĆ".repeat(50)));

				// Tasks
				if (result.tasks.added.length > 0 || result.tasks.modified.length > 0) {
					console.log(chalk.bold("\nTasks:"));
					for (const id of result.tasks.added) {
						console.log(chalk.green(`  + ${id} (new)`));
					}
					for (const mod of result.tasks.modified) {
						console.log(chalk.yellow(`  ~ ${mod.id} (${mod.changes})`));
					}
				}

				// Decisions
				if (result.decisions.added.length > 0) {
					console.log(chalk.bold("\nDecisions:"));
					console.log(
						chalk.green(`  + ${result.decisions.added.length} new decisions`),
					);
				}

				// Changelog
				if (result.changelog.added.length > 0) {
					console.log(chalk.bold("\nChangelog:"));
					console.log(
						chalk.green(`  + ${result.changelog.added.length} new entries`),
					);
				}

				// Current State
				if (result.currentState.changed) {
					console.log(chalk.bold("\nCurrent State:"));
					console.log(
						chalk.yellow(
							`  ~ Modified locally (${result.currentState.lineCount} lines)`,
						),
					);
				}

				// Summary
				console.log(chalk.gray(`\n${"ŌöĆ".repeat(50)}`));
				console.log(
					chalk.bold(`Summary: ${result.summary.totalChanges} changes`),
				);
				if (result.summary.totalChanges > 0) {
					console.log(chalk.gray("Run: vem push\n"));
				} else {
					console.log(chalk.gray("No changes to push\n"));
				}
			} catch (error: any) {
				console.error(
					chalk.red(`\nŌ£¢ Failed to generate diff: ${error.message}\n`),
				);
			}
		});

	// Doctor command
	program
		.command("doctor")
		.description("Run health checks on VEM setup")
		.option("--json", "Output as JSON")
		.action(async (options: { json?: boolean }) => {
			try {
				const { DoctorService } = await import("@vem/core");
				const doctorService = new DoctorService();

				const results = await doctorService.runAllChecks();

				if (options.json) {
					console.log(JSON.stringify(results, null, 2));
					process.exit(
						results.some((r) => r.status === "fail")
							? 2
							: results.some((r) => r.status === "warn")
								? 1
								: 0,
					);
					return;
				}

				console.log(chalk.bold("\nVEM Health Check"));
				console.log(chalk.gray("ŌöĆ".repeat(50)));

				let hasErrors = false;
				let hasWarnings = false;

				for (const result of results) {
					let icon = "";
					let color: (s: string) => string;

					if (result.status === "pass") {
						icon = "Ō£ō";
						color = chalk.green;
					} else if (result.status === "warn") {
						icon = "ŌÜĀ";
						color = chalk.yellow;
						hasWarnings = true;
					} else {
						icon = "Ō£Ś";
						color = chalk.red;
						hasErrors = true;
					}

					console.log(color(`${icon} ${result.name}`));
					console.log(chalk.gray(`  ${result.message}`));

					if (result.fix) {
						console.log(chalk.gray(`  ŌåÆ ${result.fix}`));
					}
				}

				console.log(chalk.gray("ŌöĆ".repeat(50)));

				if (hasErrors) {
					console.log(chalk.red("\nŌ£Ś Issues found that need attention\n"));
					process.exit(2);
				} else if (hasWarnings) {
					console.log(chalk.yellow("\nŌÜĀ Minor issues found\n"));
					process.exit(1);
				} else {
					console.log(chalk.green("\nŌ£ō All checks passed\n"));
					process.exit(0);
				}
			} catch (error: any) {
				console.error(
					chalk.red(`\nŌ£¢ Failed to run health checks: ${error.message}\n`),
				);
				process.exit(2);
			}
		});

	// Summarize command
	program
		.command("summarize")
		.description("Analyze current changes and suggest VEM memory updates")
		.option("--staged", "Analyze only staged changes")
		.action(async (options: { staged?: boolean }) => {
			await trackCommandUsage("summarize");
			try {
				const configService = new ConfigService();
				const key = await tryAuthenticatedKey(configService);
				const projectId = await configService.getProjectId();

				if (!key || !projectId) {
					console.error(
						chalk.red("\nŌ£¢ Authentication or project link missing.\n"),
					);
					return;
				}

				console.log(chalk.blue("Analyzing local changes..."));
				const diffCmd = options.staged ? "git diff --cached" : "git diff HEAD";
				const diff = execSync(diffCmd).toString();

				if (!diff.trim()) {
					console.log(chalk.yellow("No changes detected to summarize."));
					return;
				}

				const res = await fetch(`${API_URL}/projects/${projectId}/summarize`, {
					method: "POST",
					headers: {
						Authorization: `Bearer ${key}`,
						"Content-Type": "application/json",
						...(await buildDeviceHeaders(configService)),
					},
					body: JSON.stringify({ diff }),
				});

				if (!res.ok) {
					const data = await res.json().catch(() => ({}));
					throw new Error(data.error || "Summarization request failed");
				}

				const { suggestions } = await res.json();

				console.log(chalk.bold("\nŌ£© AI-Suggested Memory Updates"));
				console.log(chalk.gray("ŌöĆ".repeat(50)));

				if (suggestions.changelog) {
					console.log(chalk.cyan("\n[Changelog]"));
					console.log(suggestions.changelog);
				}

				if (suggestions.decisions?.length > 0) {
					console.log(chalk.cyan("\n[Decisions]"));
					suggestions.decisions.forEach((d: any) => {
						console.log(chalk.bold(`- ${d.title}`));
						console.log(chalk.gray(`  ${d.decision}`));
					});
				}

				if (suggestions.context_updates) {
					console.log(chalk.cyan("\n[Context Updates]"));
					console.log(suggestions.context_updates);
				}

				if (suggestions.current_state_updates) {
					console.log(chalk.cyan("\n[Current State Updates]"));
					console.log(suggestions.current_state_updates);
				}

				console.log(chalk.gray(`\n${"ŌöĆ".repeat(50)}`));
				console.log(
					chalk.gray(
						"Tip: Use these suggestions to update your .vem/ files before pushing.\n",
					),
				);
			} catch (error: any) {
				console.error(
					chalk.red(`\nŌ£¢ Failed to generate summary: ${error.message}\n`),
				);
			}
		});

	// --- Validation Rules ---
	const validationCmd = program
		.command("validation")
		.description("Manage validation rules (.vem/validation-rules.json)");

	validationCmd
		.command("show")
		.description("Display current validation rules")
		.action(async () => {
			try {
				const rulesService = new ValidationRulesService();
				const rules = await rulesService.readRules();
				console.log(chalk.bold("\n­¤öÆ Validation Rules\n"));
				const rows: [string, unknown][] = [
					["require_evidence_on_done", rules.require_evidence_on_done],
					[
						"require_all_tasks_done_to_close",
						rules.require_all_tasks_done_to_close,
					],
					["run_sensors_on_validate", rules.run_sensors_on_validate],
					["trigger_ai_review_on_close", rules.trigger_ai_review_on_close],
					["require_no_blocked_tasks", rules.require_no_blocked_tasks],
					["strict_mode", rules.strict_mode],
					["preferred_backend", rules.preferred_backend],
				];
				for (const [key, val] of rows) {
					const icon =
						val === true
							? chalk.green("Ō£ō")
							: val === false
								? chalk.gray("Ō£Ś")
								: chalk.cyan(String(val));
					console.log(`  ${chalk.bold(key.padEnd(40))} ${icon}`);
				}
				console.log();
			} catch (error: any) {
				console.error(chalk.red(`\nŌ£¢ ${error.message}\n`));
			}
		});

	validationCmd
		.command("edit")
		.description("Edit validation rules in $EDITOR")
		.action(async () => {
			try {
				const vemDir = await getVemDir();
				const rulesPath = path.join(vemDir, "validation-rules.json");
				// Ensure file exists with defaults
				if (!(await fs.pathExists(rulesPath))) {
					const rulesService = new ValidationRulesService();
					await rulesService.readRules(); // creates defaults
				}
				const editor = process.env.EDITOR || process.env.VISUAL || "vi";
				execSync(`${editor} "${rulesPath}"`, { stdio: "inherit" });
				console.log(chalk.green("\nŌ£ö Validation rules updated.\n"));
			} catch (error: any) {
				console.error(chalk.red(`\nŌ£¢ ${error.message}\n`));
			}
		});

	// --- Drift Check ---
	const driftCmd = program
		.command("drift")
		.description(
			"Architecture drift detection based on ADRs and recent git changes",
		);

	driftCmd
		.command("check")
		.description(
			"Check for architecture drift: ADR enforcement patterns vs recent git diff",
		)
		.option(
			"--since <ref>",
			"Git ref or ISO date to diff from (default: HEAD~30)",
		)
		.action(async (options: { since?: string }) => {
			await trackCommandUsage("drift.check");
			try {
				const cycleValidationService = new CycleValidationService();

				// Load decisions and parse enforcement_pattern from markdown content
				const decisionsLog = new ScalableLogService(DECISIONS_DIR);
				const rawDecisions = await decisionsLog.getAllEntries();

				// Parse **Enforcement Pattern:** lines from decision markdown content
				const decisions = rawDecisions
					.map((d) => {
						const match = d.content.match(
							/\*\*Enforcement Pattern:\*\*\s*(.+)/i,
						);
						return {
							id: d.id,
							title: d.title,
							enforcement_pattern: match ? match[1].trim() : undefined,
						};
					})
					.filter((d) => d.enforcement_pattern);

				if (decisions.length === 0) {
					console.log(
						chalk.yellow(
							"\nŌÜĀ  No decisions have an Enforcement Pattern set.\n",
						),
					);
					console.log(
						chalk.gray(
							"  Add '**Enforcement Pattern:** <regex>' to a decision file in .vem/decisions/",
						),
					);
					console.log(
						chalk.gray(
							"  Or use: vem decision add ... --enforcement-pattern <regex>\n",
						),
					);
					return;
				}

				const gitDiff = cycleValidationService.getGitDiffSince(options.since);
				const violations = cycleValidationService.checkDrift(
					decisions,
					gitDiff,
				);

				console.log(chalk.bold("\n­¤öŹ  Architecture Drift Check\n"));
				console.log(
					chalk.gray(
						`  Checking ${decisions.length} decision(s) with enforcement patterns...\n`,
					),
				);

				if (violations.length === 0) {
					console.log(chalk.green("  Ō£ö No drift violations detected.\n"));
				} else {
					console.log(
						chalk.red(`  Ō£¢ ${violations.length} violation(s) found:\n`),
					);
					for (const v of violations) {
						console.log(`  ${chalk.bold(v.decisionTitle)}`);
						console.log(`    File:    ${chalk.cyan(v.file)}:${v.line}`);
						console.log(`    Pattern: ${chalk.gray(v.pattern)}`);
						console.log(`    Match:   ${chalk.yellow(v.match)}\n`);
					}
					process.exitCode = 1;
				}
			} catch (error: any) {
				console.error(chalk.red(`\nŌ£¢ Drift check failed: ${error.message}\n`));
				process.exitCode = 1;
			}
		});
}
